content.content:
   1→/* ── Mobile top header ── Hidden on desktop ── */
   2→.mobile-top-header{
   3→    display: none;
   4→}
   5→.mobile-write-btn{
   6→    display: none;
   7→}
   8→
   9→.newsfeed-header{
  10→}
  11→.search-shell{
  12→    position: sticky;
  13→    top: 0;
  14→    z-index: 14;
  15→    align-self: stretch;
  16→    width: 100%;
  17→    max-width: 100%;
  18→}
  19→.search-top-bar{
  20→    position: relative;
  21→    z-index: 12;
  22→    display: flex;
  23→    align-items: center;
  24→    gap: 0.5rem;
  25→    width: 100%;
  26→    padding: 0.65rem 0.75rem 0.75rem 0.75rem;
  27→    box-sizing: border-box;
  28→    background: var(--bg-primary);
  29→    border-bottom: 1px solid var(--border-card);
  30→}
  31→.search-input-wrap{
  32→    position: relative;
  33→    display: flex;
  34→    align-items: center;
  35→    flex: 1;
  36→}
  37→.search-icon{
  38→    position: absolute;
  39→    left: 0.85rem;
  40→    width: 15px;
  41→    height: 15px;
  42→    color: var(--text-faint);
  43→    pointer-events: none;
  44→    transition: color 0.25s ease, transform 0.25s ease;
  45→}
  46→.search-input-wrap:focus-within .search-icon{
  47→    color: #D4A853;
  48→    transform: scale(1.08);
  49→}
  50→.search-input{
  51→    width: 100%;
  52→    border: 1.5px solid var(--border-card);
  53→    border-radius: 10px;
  54→    padding: 0.6rem 0.9rem 0.6rem 2.4rem;
  55→    font-family: var(--font-ui);
  56→    font-size: 0.84rem;
  57→    font-weight: 450;
  58→    letter-spacing: 0.01rem;
  59→    color: var(--text-heading);
  60→    background: var(--bg-secondary);
  61→    outline: none;
  62→    transition: border-color 0.3s ease, box-shadow 0.3s ease, background 0.3s ease;
  63→}
  64→.search-input::placeholder{
  65→    color: var(--text-faint);
  66→    font-weight: 400;
  67→    letter-spacing: 0.015rem;
  68→}
  69→.search-input:focus{
  70→    border-color: #D4A853;
  71→    background: var(--bg-card);
  72→    box-shadow:
  73→        0 0 0 3px rgba(212, 168, 83, 0.1),
  74→        0 2px 8px rgba(212, 168, 83, 0.06);
  75→}
  76→.search-clear-btn{
  77→    border: 1.5px solid var(--border-card);
  78→    background: var(--bg-secondary);
  79→    color: var(--text-secondary);
  80→    border-radius: 8px;
  81→    font-family: var(--font-ui);
  82→    font-size: 0.7rem;
  83→    font-weight: 600;
  84→    letter-spacing: 0.02rem;
  85→    padding: 0.4rem 0.72rem;
  86→    cursor: pointer;
  87→    transition: background 0.2s ease, border-color 0.2s ease, color 0.2s ease;
  88→    white-space: nowrap;
  89→}
  90→.search-clear-btn:hover{
  91→    background: var(--bg-hover);
  92→    border-color: #D4A853;
  93→    color: #D4A853;
  94→}
  95→/* ── Nav row (Freedom Wall + Stories) ── */
  96→.search-nav-row{
  97→    display: flex;
  98→    gap: 6px;
  99→    padding: 0.4rem 0.75rem;
 100→}
 101→.search-nav-btn{
 102→    display: flex;
 103→    align-items: center;
 104→    justify-content: center;
 105→    gap: 0.35rem;
 106→    flex: 1;
 107→    border-radius: 999px;
 108→    font-family: var(--font-ui);
 109→    font-size: 0.74rem;
 110→    font-weight: 700;
 111→    letter-spacing: 0.01rem;
 112→    padding: 0.48rem 0.7rem;
 113→    cursor: pointer;
 114→    white-space: nowrap;
 115→    transition: background 0.15s ease, transform 0.15s ease, box-shadow 0.15s ease;
 116→}
 117→.search-nav-btn:active{
 118→    transform: scale(0.97);
 119→}
 120→.search-nav-fw{
 121→    border: 1.5px solid rgba(234, 179, 56, 0.35);
 122→    background: linear-gradient(135deg, rgba(234, 179, 56, 0.12), rgba(255, 204, 51, 0.08));
 123→    color: #e6a817;
 124→}
 125→.search-nav-fw:hover{
 126→    background: linear-gradient(135deg, rgba(234, 179, 56, 0.22), rgba(255, 204, 51, 0.16));
 127→    box-shadow: 0 0 10px rgba(234, 179, 56, 0.15);
 128→}
 129→.search-nav-stories{
 130→    border: 1.5px solid rgba(234, 179, 56, 0.35);
 131→    background: linear-gradient(135deg, rgba(234, 179, 56, 0.12), rgba(255, 204, 51, 0.08));
 132→    color: #e6a817;
 133→}
 134→.search-nav-stories:hover{
 135→    background: linear-gradient(135deg, rgba(234, 179, 56, 0.22), rgba(255, 204, 51, 0.16));
 136→    box-shadow: 0 0 10px rgba(234, 179, 56, 0.15);
 137→}
 138→.search-nav-following{
 139→    border: 1.5px solid rgba(234, 179, 56, 0.35);
 140→    background: linear-gradient(135deg, rgba(234, 179, 56, 0.12), rgba(255, 204, 51, 0.08));
 141→    color: #e6a817;
 142→}
 143→.search-nav-following:hover{
 144→    background: linear-gradient(135deg, rgba(234, 179, 56, 0.22), rgba(255, 204, 51, 0.16));
 145→    box-shadow: 0 0 10px rgba(234, 179, 56, 0.15);
 146→}
 147→.search-nav-active{
 148→    background: linear-gradient(135deg, rgba(234, 179, 56, 0.30), rgba(255, 204, 51, 0.22));
 149→    box-shadow: 0 0 12px rgba(234, 179, 56, 0.2);
 150→    border-color: rgba(234, 179, 56, 0.55);
 151→}
 152→.search-mode-pill{
 153→    display: flex;
 154→    align-items: center;
 155→    border-radius: 8px;
 156→    border: 1.5px solid var(--border-card);
 157→    background: var(--bg-secondary);
 158→    color: var(--text-faint);
 159→    font-family: var(--font-ui);
 160→    font-size: 0.65rem;
 161→    font-weight: 650;
 162→    letter-spacing: 0.04rem;
 163→    text-transform: uppercase;
 164→    padding: 0.35rem 0.6rem;
 165→    white-space: nowrap;
 166→}
 167→.search-gallery-hint{
 168→    margin: 0 0.75rem 0.45rem 0.75rem;
 169→    width: fit-content;
 170→    border: 1.5px solid var(--border-card);
 171→    background: var(--bg-secondary);
 172→    color: var(--accent-sage);
 173→    border-radius: 8px;
 174→    font-family: var(--font-ui);
 175→    font-size: 0.68rem;
 176→    font-weight: 600;
 177→    letter-spacing: 0.01rem;
 178→    padding: 0.34rem 0.62rem;
 179→    cursor: pointer;
 180→    transition: background 0.2s ease, border-color 0.2s ease;
 181→}
 182→.search-gallery-hint:hover{
 183→    background: var(--bg-hover);
 184→    border-color: var(--accent-sage);
 185→}
 186→.search-empty-state{
 187→    display: flex;
 188→    justify-content: center;
 189→    align-items: center;
 190→    width: 100%;
 191→    padding: 2rem 0.5rem;
 192→    font-family: var(--font-ui);
 193→    font-size: 0.84rem;
 194→    font-weight: 500;
 195→    color: var(--text-faint);
 196→    letter-spacing: 0.01rem;
 197→}
 198→.search-empty-state.is-canvas-only{
 199→    flex-wrap: wrap;
 200→    gap: 0.28rem;
 201→}
 202→.search-empty-link{
 203→    border: none;
 204→    background: transparent;
 205→    color: var(--accent-sage);
 206→    font-family: var(--font-ui);
 207→    font-size: 0.84rem;
 208→    font-weight: 650;
 209→    cursor: pointer;
 210→    text-decoration: underline;
 211→}
 212→.search-empty-link:hover{
 213→    opacity: 0.88;
 214→}
 215→.search-suggestions-dropdown{
 216→    position: absolute;
 217→    left: 0.75rem;
 218→    right: 0.75rem;
 219→    top: calc(100% - 0.15rem);
 220→    z-index: 30;
 221→    border: 1.5px solid var(--border-card);
 222→    border-radius: 10px;
 223→    background: var(--bg-elevated);
 224→    box-shadow:
 225→        0 8px 24px rgba(0, 0, 0, 0.1),
 226→        0 2px 8px rgba(0, 0, 0, 0.06);
 227→    max-height: 320px;
 228→    overflow-y: auto;
 229→    padding: 0.3rem 0;
 230→    animation: searchDropdownIn 0.2s ease-out;
 231→}
 232→@keyframes searchDropdownIn{
 233→    from{
 234→        opacity: 0;
 235→        transform: translateY(-6px);
 236→    }
 237→    to{
 238→        opacity: 1;
 239→        transform: translateY(0);
 240→    }
 241→}
 242→.search-suggestion-item{
 243→    width: 100%;
 244→    text-align: left;
 245→    border: none;
 246→    background: transparent;
 247→    cursor: pointer;
 248→    display: flex;
 249→    flex-direction: column;
 250→    gap: 0.15rem;
 251→    padding: 0.6rem 0.85rem;
 252→    transition: background 0.15s ease;
 253→    border-left: 2.5px solid transparent;
 254→}
 255→.search-suggestion-item:hover{
 256→    background: var(--bg-pill);
 257→    border-left-color: #D4A853;
 258→}
 259→.search-suggestion-title{
 260→    font-family: var(--font-ui);
 261→    font-size: 0.8rem;
 262→    font-weight: 600;
 263→    color: var(--text-heading);
 264→    white-space: nowrap;
 265→    overflow: hidden;
 266→    text-overflow: ellipsis;
 267→}
 268→.search-suggestion-meta{
 269→    font-family: var(--font-ui);
 270→    font-size: 0.68rem;
 271→    font-weight: 450;
 272→    color: var(--text-faint);
 273→    letter-spacing: 0.01rem;
 274→}
 275→.search-suggestion-muted{
 276→    color: var(--text-faint);
 277→    cursor: default;
 278→    border-left-color: transparent !important;
 279→}
 280→.postcards-parent-container{
 281→    position: relative;
 282→    display: flex;
 283→    flex-direction: column;
 284→    align-items: center;
 285→    width: 100%;
 286→    margin-bottom: 1rem;
 287→    gap: 16px;
 288→    padding: 0 16px;
 289→    box-sizing: border-box;
 290→}
 291→.postcards-parent-loading-container{
 292→    position: relative;
 293→    top: 90px;
 294→    display: flex;
 295→    justify-content: center;
 296→    align-items: center;
 297→    flex-direction: column;
 298→    width: 100%;
 299→    height: 100vh;
 300→}
 301→.loading-newsfeed-bg{
 302→    display: flex;
 303→    justify-content: center;
 304→    align-items: center;
 305→    width: 100%;
 306→    height: 100%;
 307→}
 308→.jounral-view-image{
 309→    width: 400px;
 310→    height: auto;
 311→}
 312→.inview{
 313→    display: flex;
 314→    justify-content: center;
 315→    align-items: center;
 316→    width: 100%;
 317→    min-height: 35px;
 318→}
 319→
 320→/* ── Card ── */
 321→.cards{
 322→    position: relative;
 323→    display: flex;
 324→    flex-direction: column;
 325→    justify-content: flex-start;
 326→    align-items: center;
 327→    width: 99%;
 328→    max-width: 100%;
 329→    min-height: fit-content;
 330→    background-color: var(--bg-card);
 331→    border: 1px solid var(--border-card);
 332→    border-radius: 12px;
 333→    overflow: visible;
 334→    cursor: pointer;
 335→    transition: box-shadow 0.25s ease, transform 0.25s ease;
 336→}
 337→.cards:hover{
 338→    box-shadow: 0 6px 24px rgba(80, 60, 40, 0.07);
 339→    transform: translateY(-2px);
 340→}
 341→
 342→.bookmarked-content-message-container{
 343→    position: absolute;
 344→    top: 100px;
 345→    background-color: rgb(72, 208, 135);
 346→    color: rgb(255, 255, 255);
 347→    font-size: 0.78rem;
 348→    font-weight: 600;
 349→    padding: 0.45rem 1rem;
 350→    border-radius: 8px;
 351→    width: fit-content;
 352→    z-index: 11;
 353→    transition: ease-in-out 0.2s;
 354→}
 355→
 356→/* ── Banner image ── */
 357→.card-image-banner{
 358→    width: 100%;
 359→    max-height: 220px;
 360→    object-fit: cover;
 361→    display: block;
 362→    border-bottom: 1px solid var(--border-card);
 363→    border-radius: 12px 12px 0 0;
 364→    transition: opacity 0.2s ease;
 365→}
 366→.cards:hover .card-image-banner{
 367→    opacity: 0.95;
 368→}
 369→
 370→/* ── Card content area ── */
 371→.card-content{
 372→    display: flex;
 373→    flex-direction: column;
 374→    gap: 0.8rem;
 375→    width: 100%;
 376→    padding: 1rem 1.15rem 0.6rem 1.15rem;
 377→    box-sizing: border-box;
 378→}
 379→
 380→/* ── User info row ── */
 381→.user-info{
 382→    display: flex;
 383→    justify-content: space-between;
 384→    align-items: center;
 385→}
 386→.user-info-child-container{
 387→    display: flex;
 388→    align-items: center;
 389→    height: 100%;
 390→    gap: 0.4rem;
 391→    width: fit-content;
 392→}
 393→.user-avatar-container{
 394→    display: flex;
 395→    align-items: center;
 396→    justify-content: center;
 397→    width: fit-content;
 398→    height: fit-content;
 399→    cursor: pointer;
 400→}
 401→.user-info-avatar{
 402→    width: 22px;
 403→    height: 22px;
 404→    border-radius: 50%;
 405→    object-fit: cover;
 406→}
 407→.user-avatar-container.avatar-ring-legend{
 408→    border-radius: 50%;
 409→    border: 2px solid #FFD700;
 410→    box-shadow:
 411→        0 0 6px 1px rgba(255, 215, 0, 0.5),
 412→        0 0 12px 2px rgba(255, 215, 0, 0.35),
 413→        0 0 20px 4px rgba(255, 215, 0, 0.2);
 414→    animation: glow-legend 2s ease-in-out infinite alternate;
 415→}
 416→.user-avatar-container.avatar-ring-og{
 417→    border-radius: 50%;
 418→    border: 2px solid #9B59FF;
 419→    box-shadow:
 420→        0 0 6px 1px rgba(155, 89, 255, 0.5),
 421→        0 0 12px 2px rgba(155, 89, 255, 0.35),
 422→        0 0 20px 4px rgba(155, 89, 255, 0.2);
 423→    animation: glow-og 2s ease-in-out infinite alternate;
 424→}
 425→
 426→@keyframes glow-legend {
 427→    from {
 428→        box-shadow:
 429→            0 0 6px 1px rgba(255, 215, 0, 0.5),
 430→            0 0 12px 2px rgba(255, 215, 0, 0.35),
 431→            0 0 20px 4px rgba(255, 215, 0, 0.2);
 432→    }
 433→    to {
 434→        box-shadow:
 435→            0 0 8px 2px rgba(255, 215, 0, 0.6),
 436→            0 0 16px 4px rgba(255, 215, 0, 0.4),
 437→            0 0 24px 6px rgba(255, 215, 0, 0.25);
 438→    }
 439→}
 440→
 441→@keyframes glow-og {
 442→    from {
 443→        box-shadow:
 444→            0 0 6px 1px rgba(155, 89, 255, 0.5),
 445→            0 0 12px 2px rgba(155, 89, 255, 0.35),
 446→            0 0 20px 4px rgba(155, 89, 255, 0.2);
 447→    }
 448→    to {
 449→        box-shadow:
 450→            0 0 8px 2px rgba(155, 89, 255, 0.6),
 451→            0 0 16px 4px rgba(155, 89, 255, 0.4),
 452→            0 0 24px 6px rgba(155, 89, 255, 0.25);
 453→    }
 454→}
 455→.user-name-container{
 456→    display: flex;
 457→    align-items: center;
 458→    gap: 0.2rem;
 459→}
 460→.user-newsfeed-name{
 461→    font-family: var(--font-ui);
 462→    font-size: 0.78rem;
 463→    font-weight: 600;
 464→    letter-spacing: 0.005rem;
 465→    margin: 0;
 466→    padding: 0;
 467→    cursor: pointer;
 468→    color: var(--text-secondary);
 469→    transition: color 0.15s ease;
 470→}
 471→.user-newsfeed-name:hover{
 472→    text-decoration: underline;
 473→    color: var(--accent-sage);
 474→}
 475→.name-info-separator{
 476→    display: flex;
 477→    justify-content: center;
 478→    align-items: center;
 479→    width: fit-content;
 480→    height: fit-content;
 481→    color: var(--text-separator);
 482→    font-size: 0.4rem;
 483→    user-select: none;
 484→}
 485→.user-info-email-container{
 486→    display: none;
 487→}
 488→.user-info-email{
 489→    padding: 0;
 490→    margin: 0;
 491→    font-family: var(--font-ui);
 492→    font-size: 0.75rem;
 493→    font-weight: 400;
 494→    color: var(--text-faint);
 495→}
 496→.user-post-date-container{
 497→    display: flex;
 498→    justify-content: center;
 499→    align-items: center;
 500→    width: fit-content;
 501→    height: fit-content;
 502→    cursor: default;
 503→    user-select: none;
 504→}
 505→.user-post-privacy{
 506→    display: flex;
 507→    justify-content: center;
 508→    align-items: center;
 509→    width: fit-content;
 510→    height: fit-content;
 511→    cursor: default;
 512→    user-select: none;
 513→    color: var(--text-heading);
 514→}
 515→.user-post-date{
 516→    padding: 0;
 517→    margin: 0;
 518→    font-family: var(--font-ui);
 519→    font-size: 0.75rem;
 520→    font-weight: 400;
 521→    color: var(--text-faint);
 522→}
 523→.user-post-settings{
 524→    position: relative;
 525→    display: flex;
 526→    flex-direction: column;
 527→    justify-self: flex-end;
 528→    width: fit-content;
 529→    height: fit-content;
 530→    cursor: pointer;
 531→    user-select: none;
 532→    color: var(--text-heading);
 533→}
 534→.setting-modal{
 535→    display: flex;
 536→    justify-content: center;
 537→    align-items: center;
 538→    position: absolute;
 539→    right: 25px;
 540→    bottom: 10px;
 541→    width: 200px;
 542→    height: 100px;
 543→    border-radius: 10px;
 544→    z-index: 200;
 545→    background-color: var(--bg-elevated);
 546→    box-shadow: 0 8px 30px rgba(0, 0, 0, 0.12);
 547→    border: 1px solid var(--border-card);
 548→}
 549→
 550→/* ── Content (title + text) ── */
 551→.content-container{
 552→    display: flex;
 553→    flex-direction: column;
 554→    justify-content: flex-start;
 555→    align-items: flex-start;
 556→    user-select: none;
 557→    gap: 0.5rem;
 558→}
 559→.feed-text-content-container{
 560→    display: flex;
 561→    flex-direction: column;
 562→    width: 100%;
 563→    height: 100%;
 564→    justify-content: flex-start;
 565→    align-items: flex-start;
 566→    gap: 0.35rem;
 567→}
 568→.feed-title-content{
 569→    display: flex;
 570→    justify-content: center;
 571→    align-items: center;
 572→}
 573→.cards.is-canvas-card .feed-title-content{
 574→    flex-direction: row;
 575→    justify-content: flex-start;
 576→    gap: 0.45rem;
 577→}
 578→.feed-title{
 579→    margin: 0;
 580→    padding: 0;
 581→    font-family: "Lexend Deca", sans-serif;
 582→    font-size: 1.1rem;
 583→    font-weight: 700;
 584→    line-height: 1.45;
 585→    letter-spacing: -0.025rem;
 586→    color: var(--text-heading);
 587→}
 588→.feed-text-content{
 589→    padding: 0;
 590→    margin: 0;
 591→    font-family: var(--font-serif);
 592→    font-weight: 400;
 593→    color: var(--text-body);
 594→    line-height: 1.7;
 595→    font-size: 0.88rem;
 596→    letter-spacing: 0.005rem;
 597→}
 598→
 599→.canvas-card-actions{
 600→    display: flex;
 601→    flex-wrap: wrap;
 602→    gap: 0.42rem;
 603→    width: 100%;
 604→    margin-top: -0.1rem;
 605→}
 606→
 607→.canvas-card-action-btn{
 608→    border: 1px solid var(--border-card);
 609→    background: var(--bg-secondary);
 610→    color: var(--text-secondary);
 611→    border-radius: 999px;
 612→    padding: 0.3rem 0.65rem;
 613→    font-size: 0.68rem;
 614→    font-weight: 620;
 615→    cursor: pointer;
 616→    transition: border-color 0.2s ease, background 0.2s ease, color 0.2s ease;
 617→}
 618→
 619→.canvas-card-action-btn:hover{
 620→    border-color: var(--accent-sage);
 621→    color: var(--accent-sage);
 622→}
 623→
 624→.canvas-card-action-btn.is-remix{
 625→    border-color: color-mix(in srgb, var(--accent-purple) 42%, var(--border-card));
 626→    color: var(--accent-purple);
 627→}
 628→
 629→/* ── Icon bar ── */
 630→.card-icons-container{
 631→    display: flex;
 632→    flex-wrap: wrap;
 633→    width: 100%;
 634→    padding: 0.5rem 1.15rem 0.85rem 1.15rem;
 635→    min-height: 22px;
 636→    align-items: center;
 637→    justify-content: flex-start;
 638→    gap: 0.5rem;
 639→    box-sizing: border-box;
 640→    border-top: 1px solid var(--border-card);
 641→}
 642→#card-icons{
 643→    display: flex;
 644→    justify-content: center;
 645→    align-items: center;
 646→    padding: 0.35rem;
 647→    border-radius: 50%;
 648→    transition: background-color 0.2s ease;
 649→    gap: 0.3rem;
 650→}
 651→#card-icons-view{
 652→    display: flex;
 653→    justify-content: center;
 654→    align-items: center;
 655→    padding: 0.1rem;
 656→    border-radius: 50%;
 657→    transition: background-color 0.2s ease;
 658→    gap: 0.3rem;
 659→}
 660→.card-icons{
 661→    display: flex;
 662→    width: fit-content;
 663→    height: fit-content;
 664→    justify-content: center;
