 33→const normalizeInteractionFlag = (value) => {
 34→    if(typeof value === 'boolean') return value;
 35→    if(typeof value === 'string'){
 36→        const normalized = value.trim().toLowerCase();
 37→        if(normalized === 'true') return true;
 38→        if(normalized === 'false') return false;
 39→    }
 40→    if(typeof value === 'number'){
 41→        return value === 1;
 42→    }
 43→    return Boolean(value);
 44→};
 45→
 46→const normalizeCount = (value) => {
 47→    const number = Number(value);
 48→    if(!Number.isFinite(number) || number < 0){
 49→        return 0;
 50→    }
 51→    return number;
 52→};
 53→
 54→const getNextToggleCount = (isActive, currentCount) => {
 55→    return isActive
 56→        ? Math.max(0, currentCount - 1)
 57→        : currentCount + 1;
 58→};
